                          </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 18 }}>
                          <div>
                            <p style={{ fontSize: 11, fontWeight: 600, marginBottom: 6 }}>ID Document</p>
                            <div style={{ 
                              background: 'var(--surface2)', 
                              borderRadius: 12, 
                              padding: 8,
                              textAlign: 'center',
                              border: '1px solid var(--border)'
                            }}>
                              <a 
                                href={`${process.env.REACT_APP_API_URL?.replace('/api', '') || 'http://localhost:5000'}/${k.id_image_url}`} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                style={{ color: 'var(--accent)', fontSize: 12, textDecoration: 'none' }}
                              >
                                📄 View ID Document
                              </a>
                            </div>
                          </div>
                          <div>
                            <p style={{ fontSize: 11, fontWeight: 600, marginBottom: 6 }}>Selfie</p>
                            <div style={{ 
                              background: 'var(--surface2)', 
                              borderRadius: 12, 
                              padding: 8,
                              textAlign: 'center',
                              border: '1px solid var(--border)'
                            }}>
                              <a 
                                href={`${process.env.REACT_APP_API_URL?.replace('/api', '') || 'http://localhost:5000'}/${k.selfie_image_url}`} 
                                target="_blank" 
                                rel="noopener noreferrer"
                                style={{ color: 'var(--accent)', fontSize: 12, textDecoration: 'none' }}
                              >
                                📸 View Selfie
                              </a>
                            </div>
                          </div>
                        </div>

                        {showRejectModal === k.id ? (
                          <div style={{ marginBottom: 12 }}>
                            <textarea
                              className="input-field"
                              placeholder="Reason for rejection..."
                              value={rejectReason}
                              onChange={(e) => setRejectReason(e.target.value)}
                              rows={2}
                              style={{ marginBottom: 10 }}
                            />
                            <div style={{ display: 'flex', gap: 8 }}>
                              <button 
                                onClick={() => rejectKYC(k.id, rejectReason)} 
                                className="btn btn-danger"
                                disabled={!rejectReason.trim()}
                              >
                                Confirm Reject
                              </button>
                              <button 
                                onClick={() => { setShowRejectModal(null); setRejectReason(''); }} 
                                className="btn btn-ghost"
                              >
                                Cancel
                              </button>
                            </div>
                          </div>
                        ) : (
                          <div style={{ display: 'flex', gap: 12 }}>
                            <button onClick={() => approveKYC(k.id)} className="btn btn-success btn-full">
                              ✓ Approve KYC
                            </button>
                            <button onClick={() => setShowRejectModal(k.id)} className="btn btn-danger btn-full">
                              ✗ Reject KYC
                            </button>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              )}
            </>
          )}

          {/* TRANSACTIONS TAB */}
          {tab === 'transactions' && (
            <>
              <div style={{ marginBottom: 20 }}>
                <p style={{ fontSize: 14, color: 'var(--text2)' }}>
                  All platform transactions
                </p>
              </div>
              <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
                <div style={{ overflowX: 'auto' }}>
                  <table className="data-table" style={{ width: '100%' }}>
                    <thead>
                      <tr>
                        <th>User</th>
                        <th>Type</th>
                        <th>Amount</th>
                        <th>Status</th>
                        <th>Date</th>
                      </tr>
                    </thead>
                    <tbody>
                      {allTransactions.slice(0, 100).map(tx => {
                        const u = users.find(u => u.id === tx.user_id);
                        const isPositive = tx.type?.includes('deposit') || 
                                          tx.type?.includes('profit') || 
                                          tx.type?.includes('referral') ||
                                          tx.type?.includes('bonus');
                        return (
                          <tr key={tx.id}>
                            <td>{u?.first_name || 'Unknown'}</td>
                            <td style={{ textTransform: 'capitalize' }}>{tx.type?.replace(/_/g, ' ')}</td>
                            <td style={{ 
                              color: isPositive ? 'var(--green)' : 'var(--text)',
                              fontWeight: 600 
                            }}>
                              {isPositive ? '+' : '-'}{fmt(Math.abs(tx.amount))}
                            </td>
                            <td>
                              <span className={`badge ${
                                tx.status === 'completed' ? 'badge-green' : 
                                tx.status === 'pending' || tx.status === 'pending_approval' ? 'badge-gold' : 
                                'badge-red'
                              }`}>
                                {tx.status}
                              </span>
                            </td>
                            <td>{fmtDate(tx.created_at)}</td>
                          </tr>
                        );
                      })}
                    </tbody>
                  </table>
                </div>
                {allTransactions.length === 0 && (
                  <p style={{ color: 'var(--text3)', fontSize: 13, textAlign: 'center', padding: 40 }}>
                    No transactions yet
                  </p>
                )}
              </div>
            </>
          )}

          {/* BROADCAST TAB */}
          {tab === 'broadcast' && (
            <div className="card card-lg" style={{ maxWidth: 600 }}>
              <h3 style={{ fontFamily: 'var(--font-display)', fontSize: 18, fontWeight: 700, marginBottom: 20 }}>
                Send Broadcast Message
              </h3>
              <div className="input-group">
                <label className="input-label">Subject</label>
                <input
                  className="input-field"
                  placeholder="Email subject line..."
                  value={broadcastSubject}
                  onChange={(e) => setBroadcastSubject(e.target.value)}
                />
              </div>
              <div className="input-group">
                <label className="input-label">Message</label>
                <textarea
                  rows={6}
                  className="input-field"
                  placeholder="Type your broadcast message here..."
                  value={broadcastMessage}
                  onChange={(e) => setBroadcastMessage(e.target.value)}
                  style={{ resize: 'vertical' }}
                />
              </div>
              <p style={{ fontSize: 12, color: 'var(--text2)', marginBottom: 16 }}>
                This message will be sent to {stats.activeUsers} active users.
              </p>
              <div style={{ display: 'flex', gap: 12, alignItems: 'center' }}>
                <button
                  onClick={sendBroadcast}
                  disabled={broadcastLoading || !broadcastSubject.trim() || !broadcastMessage.trim()}
                  className="btn btn-primary"
                  style={{ gap: 8 }}
                >
                  {broadcastLoading ? (
                    <><span className="spinner" /> Sending...</>
                  ) : (
                    <><Icon name="broadcast" size={14} color="#fff" /> Send Broadcast</>
                  )}
                </button>
                {(broadcastSubject || broadcastMessage) && (
                  <button 
                    onClick={() => { setBroadcastSubject(''); setBroadcastMessage(''); }} 
                    className="btn btn-ghost"
                  >
                    Clear
                  </button>
                )}
              </div>

              {/* Info Card */}
              <div style={{ 
                marginTop: 28, 
                background: 'var(--surface2)', 
                borderRadius: 14, 
                padding: '16px 18px' 
              }}>
                <p style={{ fontSize: 13, fontWeight: 600, marginBottom: 10 }}>
                  <Icon name="broadcast" size={14} /> Broadcast Tips
                </p>
                <ul style={{ fontSize: 12, color: 'var(--text2)', paddingLeft: 20, lineHeight: 1.8 }}>
                  <li>Keep messages concise and professional</li>
                  <li>Include important announcements and updates</li>
                  <li>Avoid sending too frequently</li>
                  <li>All active users will receive the email</li>
                </ul>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
// ============================================================================
// MAIN APP
// ============================================================================
export default function App() {
  const { user, loading, logout } = useAuth();
  const [darkMode, setDarkMode] = useState(localStorage.getItem('darkMode') === 'true');
  const [toasts, setToasts] = useState([]);
  const toastId = useRef(0);

  useEffect(() => { localStorage.setItem('darkMode', darkMode); document.documentElement.classList.toggle('dark-mode', darkMode); }, [darkMode]);

  const showToast = useCallback((message, type = 'info') => {
    const id = ++toastId.current;
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => setToasts(prev => prev.filter(t => t.id !== id)), 3200);
  }, []);

  if (loading) return <LoadingScreen />;
  if (!user) return <><StyleInjector /><AuthScreen darkMode={darkMode} setDarkMode={setDarkMode} /><ToastContainer toasts={toasts} /></>;
  if (user.is_admin) return <><StyleInjector /><AdminDashboard darkMode={darkMode} setDarkMode={setDarkMode} onLogout={logout} showToast={showToast} /><ToastContainer toasts={toasts} /></>;
  return <><StyleInjector /><UserDashboard darkMode={darkMode} setDarkMode={setDarkMode} onLogout={logout} showToast={showToast} /><ToastContainer toasts={toasts} /></>;
}
